import java.util.*;import java.io.*;class Player{public static void main(String[]a)throws Exception{var br=new BufferedReader(new InputStreamReader(System.in));var st=new StringTokenizer(br.readLine());int W=Integer.parseInt(st.nextToken()),H=Integer.parseInt(st.nextToken());String[]img=br.readLine().split(" ");byte[]D=new byte[W*H],DC=new byte[W*H];int p=0;for(int i=0;i<img.length;i+=2){byte c=(byte)(img[i].charAt(0)=='B'?1:0);int l=Integer.parseInt(img[i+1]);for(int j=0;j<l;j++){D[p]=c;DC[p]=c;p++;}}int sc=0;while(sc<W){boolean f=false;for(int r=0;r<H;r++)if(D[r*W+sc]==1)f=true;if(f)break;sc++;}int ec=W-1;while(ec>0){boolean f=false;for(int r=0;r<H;r++)if(D[r*W+ec]==1)f=true;if(f)break;ec--;}int[]ls=new int[5],le=new int[5];int nl=0,r=0;while(r<H){if(D[r*W+sc]==1){ls[nl]=r;while(r<H&&D[r*W+sc]==1)r++;le[nl]=r-1;nl++;}r++;}int dbl=ls[1]-le[0]-1,lw=le[0]-ls[0]+1;for(int i=0;i<5;i++)for(r=ls[i];r<=le[i];r++)for(int c=0;c<W;c++)D[r*W+c]=0;for(r=ls[4]+dbl+lw;r<=le[4]+lw+dbl&&r<H;r++)for(int c=0;c<W;c++)D[r*W+c]=0;double[]NY=new double[12];NY[0]=(ls[4]+le[4])/2.0+dbl;NY[1]=(ls[4]+le[4])/2.0+dbl/2.0;NY[2]=(ls[4]+le[4])/2.0;NY[3]=(ls[4]+le[3])/2.0;NY[4]=(ls[3]+le[3])/2.0;NY[5]=(ls[3]+le[2])/2.0;NY[6]=(ls[2]+le[2])/2.0;NY[7]=(ls[2]+le[1])/2.0;NY[8]=(ls[1]+le[1])/2.0;NY[9]=(ls[1]+le[0])/2.0;NY[10]=(ls[0]+le[0])/2.0;NY[11]=(ls[0]+le[0])/2.0-dbl/2.0;String P="CDEFGABCDEFG";int[]nv=new int[W];for(int c=0;c<W;c++){int n=0;for(r=0;r<H;r++)if(D[r*W+c]==1)n++;nv[c]=n;}int[]ns=new int[1000],ne=new int[1000];int nn=0;boolean pv=false;int c=sc;while(c<=ec){if(nv[c]==nv[sc]){if(pv&&nn>0)ne[nn-1]=c;while(c<=ec&&nv[c]==nv[sc])c++;ns[nn]=c;nn++;pv=true;}c++;}nn--;if(nn>0)ne[nn-1]=Math.max(ne[nn-1],ns[nn-1]);for(c=0;c<W;c++)if(nv[c]>dbl)for(r=0;r<H;r++)D[r*W+c]=0;var sb=new StringBuilder();for(int i=0;i<nn;i++){if(ne[i]<ns[i])ne[i]=ns[i];int w=0;double cy=0;for(c=ns[i];c<=ne[i];c++)for(r=0;r<H;r++)if(D[r*W+c]==1){w++;cy+=r;}if(w==0)continue;cy/=w;int sr=(int)Math.round(cy),sm=(ns[i]+ne[i])/2;char tp=DC[sr*W+sm]==1?'Q':'H';double md=1e9;int pi=0;for(int j=0;j<12;j++){double d=Math.abs(cy-NY[j]);if(d<md){md=d;pi=j;}}if(sb.length()>0)sb.append(' ');sb.append(P.charAt(pi));sb.append(tp);}System.out.println(sb);}}
